randomNumber:
MODULE RandomNumbers;
  IMPORT Out, Math;

  VAR seed: LONGINT;

  PROCEDURE SetSeed(val: LONGINT);
  BEGIN
    seed := val
  END SetSeed;

  PROCEDURE Random(): LONGINT;
    CONST a = 1664525; c = 1013904223;
  BEGIN
    seed := (seed * a + c);
    RETURN seed
  END Random;

  PROCEDURE RandomRange(min, max: LONGINT): LONGINT;
  BEGIN
    RETURN min + (ABS(Random()) MOD (max - min + 1))
  END RandomRange;

BEGIN
  SetSeed(12345); (* Set a fixed seed for predictable output *)
  Out.String("Random Integer [1-100]: "); Out.LongInt(RandomRange(1, 100), 0); Out.Ln;
  Out.String("Random Float [0.0-1.0): "); Out.Real(ABS(FLOAT(Random())) / 2147483647.0, 10); Out.Ln;
END RandomNumbers.

reverseString:
MODULE ReverseString;
  IMPORT Out, Texts;

  PROCEDURE Reverse(s: ARRAY OF CHAR; VAR res: ARRAY OF CHAR);
    VAR i, len: INTEGER;
  BEGIN
    len := 0;
    WHILE (len < LEN(s)) & (s[len] # 0X) DO INC(len) END;

    IF len > LEN(res)-1 THEN len := LEN(res)-1 END;

    i := 0;
    WHILE i < len DO
      res[i] := s[len - 1 - i];
      INC(i);
    END;
    res[len] := 0X; (* Null-terminate the result *)
  END Reverse;

  VAR 
    original: ARRAY 32 OF CHAR;
    reversed: ARRAY 32 OF CHAR;
BEGIN
  original := "Hello, Oberon!";
  Reverse(original, reversed);
  Out.String("Original: "); Out.String(original); Out.Ln;
  Out.String("Reversed: "); Out.String(reversed); Out.Ln;
END ReverseString.

fibonacci:
MODULE Fibonacci;
  IMPORT Out;

  PROCEDURE Fib(n: INTEGER): LONGINT;
    VAR a, b, temp: LONGINT;
        i: INTEGER;
  BEGIN
    IF n = 0 THEN RETURN 0 END;
    a := 0; b := 1;
    FOR i := 2 TO n DO
      temp := a + b;
      a := b;
      b := temp;
    END;
    RETURN b;
  END Fib;

BEGIN
  Out.String("First 15 Fibonacci numbers:"); Out.Ln;
  FOR i := 0 TO 14 DO
    Out.LongInt(Fib(i), 8);
  END;
  Out.Ln;
END Fibonacci.

factorial:
MODULE Factorial;
  IMPORT Out;

  PROCEDURE Fact(n: INTEGER): LONGINT;
    VAR res: LONGINT; i: INTEGER;
  BEGIN
    IF n < 0 THEN RETURN -1 END;
    res := 1;
    FOR i := 2 TO n DO
      res := res * i;
    END;
    RETURN res;
  END Fact;

BEGIN
  Out.String("Factorial of 5 is "); Out.LongInt(Fact(5), 0); Out.Ln;
  Out.String("Factorial of 0 is "); Out.LongInt(Fact(0), 0); Out.Ln;
  Out.String("Factorial of 12 is "); Out.LongInt(Fact(12), 0);
END Factorial.

primeCheck:
MODULE PrimeCheck;
  IMPORT Out, Math;

  PROCEDURE IsPrime(n: LONGINT): BOOLEAN;
    VAR i, limit: LONGINT;
  BEGIN
    IF n <= 1 THEN RETURN FALSE END;
    IF n <= 3 THEN RETURN TRUE END;
    IF (n MOD 2 = 0) OR (n MOD 3 = 0) THEN RETURN FALSE END;

    limit := ENTIER(Math.sqrt(FLOAT(n)));
    i := 5;
    WHILE i <= limit DO
      IF (n MOD i = 0) OR (n MOD (i + 2) = 0) THEN
        RETURN FALSE;
      END;
      INC(i, 6);
    END;
    RETURN TRUE;
  END IsPrime;

  VAR num: LONGINT;
BEGIN
  num := 29;
  Out.LongInt(num, 0); 
  IF IsPrime(num) THEN Out.String(" is prime.") ELSE Out.String(" is not prime.") END;
  Out.Ln;

  num := 10;
  Out.LongInt(num, 0); 
  IF IsPrime(num) THEN Out.String(" is prime.") ELSE Out.String(" is not prime.") END;
  Out.Ln;
END PrimeCheck.

readFile:
MODULE ReadFile;
  IMPORT Files, Out;

  PROCEDURE ReadLines(name: ARRAY OF CHAR);
    VAR F: Files.File; R: Files.Rider;
        line: ARRAY 256 OF CHAR;
  BEGIN
    F := Files.Old(name);
    IF F = NIL THEN
      Out.String("Error: File not found: "); Out.String(name); Out.Ln;
      RETURN;
    END;

    Files.Set(R, F, 0); (* Position rider at the beginning *)
    Out.String("--- Content of "); Out.String(name); Out.String(" ---"); Out.Ln;

    Files.ReadString(R, line);
    WHILE ~R.eot DO
      Out.String(line); Out.Ln;
      Files.ReadString(R, line);
    END;
  END ReadLines;

BEGIN
  (* First, create a dummy file to read *)
  VAR F: Files.File; R: Files.Rider;
  F := Files.New("oberon_read_test.txt");
  Files.Set(R, F, 0);
  Files.WriteString(R, "First line from Oberon.\n");
  Files.WriteString(R, "Second line.\n");
  Files.Register(F);

  ReadLines("oberon_read_test.txt");
END ReadFile.

writeFile:
MODULE WriteFile;
  IMPORT Files, Out;

  PROCEDURE WriteNew(name: ARRAY OF CHAR);
    VAR F: Files.File; R: Files.Rider;
  BEGIN
    Out.String("--- Writing (overwrite) to "); Out.String(name); Out.String(" ---"); Out.Ln;
    F := Files.New(name); (* Creates or truncates the file *)
    Files.Set(R, F, 0); (* Position rider at the beginning *)

    Files.WriteString(R, "This line overwrites existing content.\n");
    Files.WriteString(R, "Written from an Oberon program.\n");

    Files.Register(F); (* Saves the file to disk *)
    Out.String("Content written successfully."); Out.Ln;
  END WriteNew;

  PROCEDURE Append(name: ARRAY OF CHAR);
    VAR F: Files.File; R: Files.Rider;
  BEGIN
    Out.String("\n--- Appending to "); Out.String(name); Out.String(" ---"); Out.Ln;
    F := Files.Old(name); (* Open existing file *)
    IF F # NIL THEN
      Files.Set(R, F, Files.Length(F)); (* Position rider at the end *)
      Files.WriteString(R, "This line was appended.\n");
      Files.Register(F);
      Out.String("Content appended successfully."); Out.Ln;
    ELSE
      Out.String("File not found for appending."); Out.Ln;
    END;
  END Append;

BEGIN
  WriteNew("output_oberon.txt");
  Append("output_oberon.txt");
END WriteFile.

fileExists:
MODULE FileExists;
  IMPORT Files, Out;

  PROCEDURE Exists(name: ARRAY OF CHAR): BOOLEAN;
    VAR F: Files.File;
  BEGIN
    F := Files.Old(name); (* Try to get a handle to the file *)
    RETURN F # NIL;
  END Exists;

BEGIN
  Out.String("Checking 'output_oberon.txt': ");
  IF Exists("output_oberon.txt") THEN Out.String("Exists") ELSE Out.String("Does NOT exist") END;
  Out.Ln;

  Out.String("Checking 'no_such_file.mod': ");
  IF Exists("no_such_file.mod") THEN Out.String("Exists") ELSE Out.String("Does NOT exist") END;
  Out.Ln;
END FileExists.

dateTime:
MODULE DateTime;
  IMPORT Out, Time;

  PROCEDURE ShowCurrentTime;
    VAR t, d: LONGINT;
        year, month, day, hour, minute, second: INTEGER;
  BEGIN
    Time.Get(t, d); (* Get time and date *)

    (* Decode the date value *)
    year := SHORT(d DIV 10000H);
    month := SHORT((d MOD 10000H) DIV 100H);
    day := SHORT(d MOD 100H);

    (* Decode the time value (seconds since midnight) *)
    hour := SHORT(t DIV 3600);
    minute := SHORT((t MOD 3600) DIV 60);
    second := SHORT(t MOD 60);

    Out.String("--- Current Date and Time ---"); Out.Ln;
    Out.String("Year: "); Out.Int(year, 0); Out.Ln;
    Out.String("Month: "); Out.Int(month, 0); Out.Ln;
    Out.String("Day: "); Out.Int(day, 0); Out.Ln;
    Out.String("Hour: "); Out.Int(hour, 0); Out.Ln;
    Out.String("Minute: "); Out.Int(minute, 0); Out.Ln;
    Out.String("Second: "); Out.Int(second, 0); Out.Ln;
  END ShowCurrentTime;

BEGIN
  ShowCurrentTime;
END DateTime.

maxInArray:
MODULE MaxInArray;
  IMPORT Out;

  PROCEDURE Max(a: ARRAY OF LONGINT): LONGINT;
    VAR i: INTEGER;
        maxVal: LONGINT;
  BEGIN
    ASSERT(LEN(a) > 0, 100); (* Assert array is not empty *)
    maxVal := a[0];
    FOR i := 1 TO LEN(a)-1 DO
      IF a[i] > maxVal THEN
        maxVal := a[i];
      END;
    END;
    RETURN maxVal;
  END Max;

  VAR 
    numbers: ARRAY 9 OF LONGINT;
BEGIN
  numbers[0] := 10; numbers[1] := 5; numbers[2] := 42; numbers[3] := 17;
  numbers[4] := 8; numbers[5] := 99; numbers[6] := 32; numbers[7] := -5;
  numbers[8] := 0;

  Out.String("Array: [10, 5, 42, 17, 8, 99, 32, -5, 0]"); Out.Ln;
  Out.String("Maximum value: "); Out.LongInt(Max(numbers), 0); Out.Ln;
END MaxInArray.
